const Q_BIOLOGY_2008=[{"id": "objective>Biology>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In terms of the number of individuals, which of the following taxa is most inclusive?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Order</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Family </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Class</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Species</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In terms of the number of individuals, the taxon that is most inclusive is the Class. The hierarchy of biological classification from most inclusive to least inclusive is: Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species. Therefore, a Class includes more individuals than an Order, Family, or Species.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic that can possibly be shared by both living and non-living organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Locomotion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Irritability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in biomass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in size </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Both living and non-living organisms can increase in size. For example, a rock (non-living) can increase in size through accumulation of other minerals, and a tree (living) grows larger as it matures.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cell of an onion bulb can be differentiated from a cheek cell by the presence of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Plasmalemma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chloroplast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell wall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nucleus</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cell of an onion bulb can be differentiated from a cheek cell by the presence of a cell wall. The cell wall is a rigid layer that is found outside the cell membrane and provides additional support and protection. Animal cells, such as cheek cells, do not have a cell wall.</div>", "topic": "LIVING ORGANISMS : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS"}, {"id": "objective>Biology>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the organisms is characterized by the possession of a chitinous exoskeleton?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I is characterized by the possession of a chitinous exoskeleton. I is an arthropod which possesses chitin.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The type of reproduction illustrated in IV is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sexual</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conjugation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">binary fission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budding</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Budding is a form of asexual reproduction in which a new organism develops from an outgrowth or bud due to cell division at one particular site. </div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the structure that performs a similar function with the testis in mammals is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stigma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">filament</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anther</div>", "<div style=\"font-family:Cambria;font-size:17px;\">receptacle</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In plants, the structure that performs a similar function with the testis in mammals is the anther. The anther is part of the stamen (male reproductive organ in flowering plants) and is responsible for the production of pollen, which is equivalent to sperm production in mammals.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bacteria type that are arranged in chains are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Staphylococci</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clostridia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Streptococci</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bacilli</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bacteria type that are arranged in chains are the Streptococci. The term 'Streptococci' is derived from Greek words 'streptos' meaning chain and 'kokkos' meaning berry. This is because these bacteria are usually found in chains or pairs, after division along a single axis.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : MONERA"}, {"id": "objective>Biology>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most abundant group of organisms in the animal kingdom is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mammalia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Annelida</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Insecta</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insects are the most diverse and abundant group of organisms in the animal kingdom, with more than a million described species and potentially representing over 90% of the differing animal life forms on Earth.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Radial symmetry is a feature common to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">platyhelminthes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nematodes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coelenterates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arthropods</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radial symmetry is the arrangement of body parts around a central axis, like spokes on a wheel. This type of symmetry is found in simple organisms such as the sea anemone, a member of the phylum Cnidaria (Coelenterata).</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used mainly for balancing in fish?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The caudal fin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The pectoral fin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The anal fin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The dorsal fin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dorsal fin helps a fish to keep its balance in the water. Without a dorsal fin, a fish would roll over onto its side.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The beak of a duck is structurally adapted for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">scooping and sieving food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">catching and grasping food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">picking and cracking food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boring and sucking food</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The beak of a duck is broad and flat, and is adapted for scooping and sieving food from the water. This is because ducks are often 'dabbling ducks' - they feed in the water by tipping forward and grazing on underwater plants.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important characteristics that makes reptiles to conquer terrestrial habitats is the possession of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">long tail</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scaly skin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sharp claw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amniotic egg</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most important characteristic that allows reptiles to conquer terrestrial habitats is the possession of an amniotic egg. The amniotic egg provides a complete environment for the developing embryo, including a shell for protection and membranes for nourishment and waste removal. This allows reptiles to lay their eggs on land, away from the water, which gives them a significant advantage in colonizing a wide range of terrestrial habitats.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a dicotyledonous stem, the zone between the epidermis and the pericycle is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stele</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xylem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phloem</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a dicotyledonous stem, the zone between the epidermis (outer layer) and the pericycle (a layer of cells surrounding the vascular tissue) is the cortex. The cortex is a tissue of the stem or root of a plant, lying between the epidermis and the vascular tissue. It is mostly made up of relatively unspecialized cells, with large intercellular spaces.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The order of passage of food in the digestive system is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ileum → caecum → large intestine → rectum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ileum → colon → caecum → rectum </div>", "<div style=\"font-family:Cambria;font-size:17px;\">large intestine → ileum → caecum → rectum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colon → caecum → ileum → rectum</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The order of passage of food in the digestive system is from the ileum to the caecum, then to the large intestine, and finally to the rectum. The ileum is the final part of the small intestine where most of the absorption of nutrients occurs. The caecum is a pouch at the beginning of the large intestine that receives chyme from the ileum, and connects to the colon. The large intestine absorbs water and electrolytes from the remaining indigestible food matter, and then passes it to the rectum for expulsion from the body.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insectivorous plants trap and kill their prey to derive</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">phosphorus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">zinc </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insectivorous plants trap and kill their prey to derive nitrogen. Nitrogen is a vital nutrient for plants, but it is scarce in the soil where insectivorous plants grow. Therefore, these plants have evolved to derive the necessary nitrogen by trapping and digesting insects.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Water reabsorption takes place in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled III is the digestive system  and IV is the excretory system.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The vessel that carries blood from I to II is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pulmonary artery</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary vein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carotid artery </div>", "<div style=\"font-family:Cambria;font-size:17px;\">jugular vein</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pulmonary artery carries deoxygenated blood to the lungs to get oxygenated .</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the alimentary system of a bird, the function of teeth is carried out by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crop</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beak</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gizzard </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tongue</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the alimentary system of a bird, the function of teeth is carried out by the gizzard. Birds do not have teeth to grind their food. Instead, they have a specialized stomach, known as a gizzard, where the grinding of food occurs. The gizzard contains small stones, which the bird swallows, that aid in the mechanical breakdown of food.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What will happen when two equal sized pieces of unripe pawpaw labelled X and Y are dropped into equal volumes of concentrated salt solution and distilled water respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pawpaw <strong>X</strong> will become turgid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both will increase in size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pawpaw <strong>Y</strong> will become turgid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both will decrease in size </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a piece of unripe pawpaw is dropped into distilled water, it will become turgid. This is due to the process of osmosis, where water molecules move from an area of lower solute concentration (the distilled water) to an area of higher solute concentration (the pawpaw), causing the pawpaw to swell or become turgid.</div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Exhaled air differs from inhaled air in that it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contains less amount of carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is usually lower in temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">often has more oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">usually has more water vapour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Exhaled air usually has more water vapour than inhaled air. This is because the respiratory system adds moisture (water vapour) to the air during the process of respiration, as the air passes through the nasal passages and the lungs.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the mammalian kidney, the Bowman's capsule is located in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ureter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pelvis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cortex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Medulla</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the mammalian kidney, the Bowman's capsule is located in the cortex. The cortex is the outer part of the kidney, and it contains the renal corpuscles, which are made up of the Bowman's capsule and the glomerulus.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A plant parenchyma cell also acts as a supporting tissue when it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">becomes flaccid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains crystals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">becomes turgid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is pigmented</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A plant parenchyma cell acts as a supporting tissue when it becomes turgid. Turgidity refers to the state of being swollen due to high fluid content. In the context of plant cells, turgidity is achieved when water enters the cell, causing it to swell and become rigid. This rigidity provides support to the plant.</div>", "topic": "SUPPORT AND MOVEMENT : SUPPORTING TISSUES IN ANIMALS"}, {"id": "objective>Biology>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The illustration is a typical example of a plant pollinated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wind </div>", "<div style=\"font-family:Cambria;font-size:17px;\">man </div>", "<div style=\"font-family:Cambria;font-size:17px;\">insects </div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wind, It is pollinated because it pollen grains are small, smooth, non-sticky and light, and also it anther are attached to the flower in such a way that they readily swing in the air to release the pollen grains.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The male inflorescence is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled I is the male inflorescence. To identify the male inflorescence (tassel) in a maize plant, look for the large, cylindrical structure at the top of the plant. It consists of spike-like structures with yellowish or light green color, containing clusters of flowers that produce pollen for fertilization. So option I is correct.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During ovulation, an egg is released from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">corpus luteum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ovarian funnel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">graafian follicle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fallopian tube</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During ovulation, an egg is released from the graafian follicle. The graafian follicle is a mature follicle in the ovary that contains the developing ovum (egg). When the follicle ruptures, it releases the egg, which is then ready for fertilization.</div>", "topic": "REPRODUCTION : REPRODUCTION IN MAMMALS"}, {"id": "objective>Biology>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled I represents the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stationary phase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lag phase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">log phase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">steady phase</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">lag phase. The part labelled I is the lag phase.In a growth curve, the lag phase is the initial phase where bacteria or other microorganisms adapt to their new environment. During this phase, there is little to no increase in cell number as the organisms are adjusting to the growth medium, synthesizing enzymes, and preparing for active growth. The length of the lag phase can vary depending on factors such as the organism's metabolic state and the composition of the growth medium. Once the lag phase ends, the organisms enter the exponential (log) phase where they grow and divide at their maximum rate.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The part labelled <strong>IV</strong> indicates that the yeast population has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reached its maximum size </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reached senescence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stopped metabolizing food </div>", "<div style=\"font-family:Cambria;font-size:17px;\">started dying</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It indicates reached its maximum size. The plateau or stationary phase is labelled IV in the graph. in a growth curve occurs when microorganisms stabilize in number due to balanced growth and death rates. This phase follows the exponential growth phase and is characterized by metabolic adjustments and survival strategies in response to limited resources or environmental stressors.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The transmission of impulses along a nerve fibre is characterized by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hormonal and temperature changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrical and ionic changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hormonal changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrostatic changes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The transmission of impulses along a nerve fibre is characterized by electrical and ionic changes. When a nerve impulse is transmitted, there is a change in the electrical potential of the nerve fiber due to the movement of ions (such as sodium and potassium) across the nerve membrane. This is known as an action potential.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major consequence of bush burning in an ecosystem is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the loss of water absorbing ability of the soil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the loss of biological diversity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in animal population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in soil fertility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bush burning in an ecosystem leads to the loss of biological diversity. This is because the fire destroys the habitats of various organisms, leading to a decrease in the number of species in that area. The other options are also consequences of bush burning, but the major consequence is the loss of biological diversity.</div>", "topic": "HUMANS AND ENVIRONMENT : CONSERVATION OF NATURAL RESOURCES"}, {"id": "objective>Biology>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following associations is an example of mutualism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydra viridis and zoochlorellae </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Human and Lice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Shark and Remora fish</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bread and Rhizopus stolonifer </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydra viridis and zoochlorellae exhibit a mutualistic relationship. Mutualism is a type of symbiotic relationship where both organisms benefit. In this case, the Hydra viridis provides the zoochlorellae with protection and nutrients, while the zoochlorellae provide the Hydra viridis with oxygen and food through photosynthesis.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a typical freshwater habitat, the edge of the stream or pond constitutes the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tidal zone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intertidal zone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">littoral zone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">euphotic zone </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a typical freshwater habitat, the edge of the stream or pond constitutes the littoral zone. The littoral zone is the part of a body of water that is close to the shore. In contrast, the tidal zone is the area that is above water at low tide and under water at high tide, the intertidal zone is the area between the high tide and low tide, and the euphotic zone is the layer of water that sunlight can penetrate, allowing photosynthesis to occur.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main ecological problem facing intertidal organisms is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">desiccation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">floatation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salinity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main ecological problem facing intertidal organisms is desiccation. Intertidal organisms live in the area between high tide and low tide, and are therefore exposed to air and sunlight at low tide. This can cause them to dry out, or desiccate, which is a major challenge for these organisms. None of the other options (floatation, salinity, humidity) pose as significant a problem as desiccation.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Stomata of some plants are sunken and protected by hairs. These are features of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mesophytes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">epiphytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xerophytes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stomata of some plants are sunken and protected by hairs. These are features of xerophytes. Xerophytes are plants that are adapted to live in dry conditions, such as deserts. The sunken stomata and protective hairs help to reduce water loss from the plant, enabling it to survive in arid environments. The other options (mesophytes, epiphytes, hydrophytes) do not typically have these adaptations.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ecological factor that will have the most limiting effect on the abundance of phytoplankton in a turbid pond is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ecological factor that will have the most limiting effect on the abundance of phytoplankton in a turbid pond is light. Phytoplankton are photosynthetic organisms that require light to produce food. In a turbid, or murky, pond, light penetration is reduced, limiting the amount of light available for photosynthesis and therefore limiting the abundance of phytoplankton. The other options (pH, oxygen, temperature) can also affect phytoplankton abundance, but not as significantly as light in a turbid pond.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> If species <strong>I</strong>, <strong>II</strong> and <strong>III</strong> interact in a community, which of the following statements is true?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The population of species <strong>II</strong> is growing at a slow rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The population of species <strong>III</strong> has reached its carrying capacity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The population of species <strong>I</strong> has become extinct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The population of species <strong>I</strong> is always higher than species <strong>II</strong></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population of species <strong>I</strong> has become extinct.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the graph below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The population size of species <strong>II</strong> on the 20th day is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population size of species <strong>II</strong> on the 20th day is 200.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to determine the percentage of air in a soil sample, the following readings were recorded:  <br/>  Volume of water in a measuring cylinder = 500cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  Volume of soil added to water = 350cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  Volume of water and soil after stirring = 800cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  The percentage of air in the soil sample is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6.25%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.36%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.28%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">43.28%</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of the soil is 350cm^3 and the volume of the water and soil after stirring is 800cm^3. The volume of the air in the soil is 800cm^3 - 500cm^3 = 300cm^3. Therefore, the percentage of air in the soil is (300cm^3 / 350cm^3) * 100% = 14.28%, which corresponds to option 3.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A boy who is fond of swimming in a pond finds himself passing urine with traces of blood. He is likely to have contracted</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">schistosomiasis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ochocerciasis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poliomyelitis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">salmonellosis</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Schistosomiasis, also known as snail fever and bilharzia, is a disease caused by parasitic flatworms called schistosomes. The urinary tract or the intestines may be infected. Symptoms include abdominal pain, diarrhea, bloody stool, or blood in the urine. Those who have been infected for a long time may experience liver damage, kidney failure, infertility, or bladder cancer. In children, it may cause poor growth and learning difficulty.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The easiest way to establish the level of pollution in a local stream is to measure the level of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkalinity</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The level of dissolved oxygen in water is directly related to the health and quality of the aquatic environment. A decrease in the level of dissolved oxygen can indicate a high level of pollution, as many pollutants can consume oxygen as they decompose. Therefore, measuring the level of oxygen in a stream can provide a good indication of its pollution level.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a major cause of variation among organisms?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Inbreeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Backcrossing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sexual reproduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gene dominance</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sexual reproduction is a major cause of variation among organisms. This is because during sexual reproduction, genes from two parents combine in unique ways during meiosis and fertilization. This leads to offspring that are genetically different from their parents and each other, causing variation.</div>", "topic": "VARIATION IN POPULATION : MORPHOLOGICAL VARIATIONS"}, {"id": "objective>Biology>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Rhesus factor of blood was first identified in a category of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">monkeys</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human females</div>", "<div style=\"font-family:Cambria;font-size:17px;\">human males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chimpanzees</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Rhesus factor of blood was first identified in a category of monkeys. The Rhesus factor is a type of antigen present on the surface of red blood cells. It was first discovered in Rhesus monkeys, which is where it gets its name.</div>", "topic": "HEREDITY : BLOOD GROUPS"}, {"id": "objective>Biology>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the four offspring of the cross will be short if <strong>T</strong> the gene for tallness is dominant to <strong>t</strong>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IV, The result of the crossing of each of them is I = TT, II = Tt, III =  Tt, Iv = tt</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The genotypic ratio of the offspring of the cross is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:1:1:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3:1</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The genotypic ratio of the offspring of the cross is 1:2:1. <br/> TT Tt tt</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Genetically modified food products have not become universally accepted because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are not tasty as others produced by conventional means</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are usually costlier than others produced by conventional means</div>", "<div style=\"font-family:Cambria;font-size:17px;\">their effects on human consumers is not yet fully understood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the technology can be applied only in developed countries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Genetically modified food products have not become universally accepted because their effects on human consumers is not yet fully understood. While genetically modified foods can have many benefits, such as increased yield and resistance to pests, there are concerns about potential health effects, environmental impact, and ethical considerations. As a result, they have not been universally accepted.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major adaptive feature of endoparasites is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loss of the organ of movement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of claws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss of the central nervous system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">presence of piercing mouthparts</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Endoparasites are organisms that live inside the body of another organism (the host). A major adaptive feature of endoparasites is the loss of the organ of movement. This is because they do not need to move in search of food or mates, as they live inside their host. Their survival and reproduction are often facilitated by the host's body.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> From the graph above, it can be appropriately deduced that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the body temperature in <strong>II</strong> varies with that in <strong>I</strong></div>", "<div style=\"font-family:Cambria;font-size:17px;\">the body temperature in <strong>I</strong> is independent of external temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I</strong> and <strong>II</strong> maintain constant body temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">external temperatures affect the body temperature of <strong>I</strong> and <strong>II</strong></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The body temperature in <strong>I</strong> is independent of external temperature. Organisms with such constant body temperature are called Homeothermes. Homeothermic organisms, like birds and mammals, maintain a constant high body temperature regardless of external conditions. They achieve this through metabolic heat production, insulation (fur, feathers, fat), behavioral adjustments, and physiological responses (sweating, panting, shivering). This ability allows them to live in diverse environments</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The animal represented by <strong>I</strong> is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poikilotherm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homeotherm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carnivore</div>", "<div style=\"font-family:Cambria;font-size:17px;\">herbivore</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Homeothermic organisms, like birds and mammals, maintain a constant high body temperature regardless of external conditions. They achieve this through metabolic heat production, insulation (fur, feathers, fat), behavioral adjustments, and physiological responses (sweating, panting, shivering). This ability allows them to live in diverse environments.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of a chameleon to change its colour is an adaptive feature for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">attraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">display</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attack</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of a chameleon to change its colour is an adaptive feature for defence. Chameleons change their colour to blend in with their surroundings and avoid predators, a phenomenon known as camouflage.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the most advanced evolutionary development in plants?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Possession of unicellular structures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of flowers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dispersal of spores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Development of secondary thickening </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most advanced evolutionary development in plants is the development of flowers. Flowers are the reproductive organs of flowering plants, and their development represents a significant evolutionary advancement. They allow for sexual reproduction and the production of seeds, which can be dispersed to produce new plants.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The natural process that produces adaptive evolutionary changes is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gene flow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">genetic drift</div>", "<div style=\"font-family:Cambria;font-size:17px;\">natural selection</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The natural process that produces adaptive evolutionary changes is natural selection. Natural selection is a process where organisms that are better adapted to their environment tend to survive and produce more offspring. This process causes species to change over time. Mutation, gene flow, and genetic drift are all mechanisms of evolution, but they do not necessarily produce adaptive evolutionary changes.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}];
